#Select all properties of the concept "water"

PREFIX skos: <http://www.w3.org/2004/02/skos/core#> 
PREFIX skosxl: <http://www.w3.org/2008/05/skos-xl#> 

SELECT DISTINCT ?property ?value ?label 
WHERE { 
  <http://aims.fao.org/aos/agrovoc/c_8309> ?property ?value . 
  OPTIONAL {
    ?value a skosxl:Label .
    ?value skosxl:literalForm ?label 
  }
}
